import json
from http.server import BaseHTTPRequestHandler, HTTPServer

class SimpleRouter:
    def __init__(self):
        self.routes = {'GET': {}, 'POST': {}}

    def add_route(self, method, path, handler):
        if method in self.routes:
            self.routes[method][path] = handler

    def get(self, path):
        def wrapper(handler):
            self.add_route('GET', path, handler)
            return handler
        return wrapper

    def post(self, path):
        def wrapper(handler):
            self.add_route('POST', path, handler)
            return handler
        return wrapper

    def resolve(self, method, path):
        return self.routes.get(method, {}).get(path, None)

class SimpleMiddleware:
    def __init__(self):
        self.middlewares = []

    def use(self, middleware):
        self.middlewares.append(middleware)

    def apply(self, request, response):
        for middleware in self.middlewares:
            middleware(request, response)

class SimpleAPI(BaseHTTPRequestHandler):
    router = SimpleRouter()
    middleware = SimpleMiddleware()

    def do_GET(self):
        self.handle_request('GET')

    def do_POST(self):
        self.handle_request('POST')

    def handle_request(self, method):
        handler = self.router.resolve(method, self.path)
        if handler:
            content_length = int(self.headers.get('Content-Length', 0))
            body = self.rfile.read(content_length).decode('utf-8') if content_length > 0 else '{}'
            try:
                request_data = json.loads(body)
            except json.JSONDecodeError:
                self.send_response(400)
                self.end_headers()
                self.wfile.write(b'Invalid JSON')
                return

            request = {'method': method, 'path': self.path, 'body': request_data}
            response = {'status': 200, 'body': {}}

            self.middleware.apply(request, response)
            handler(request, response)

            self.send_response(response['status'])
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps(response['body']).encode('utf-8'))
        else:
            self.send_response(404)
            self.end_headers()
            self.wfile.write(b'Not Found')

    @classmethod
    def route(cls, method, path):
        return cls.router.add_route(method, path)

    @classmethod
    def use(cls, middleware):
        cls.middleware.use(middleware)

def run(server_class=HTTPServer, handler_class=SimpleAPI, port=8080):
    server_address = ('', port)
    httpd = server_class(server_address, handler_class)
    print(f'Starting server on port {port}')
    httpd.serve_forever()

# Example usage
api = SimpleAPI

@api.route('GET', '/hello')
def hello_world(request, response):
    response['body'] = {'message': 'Hello, World!'}

@api.route('POST', '/echo')
def echo(request, response):
    response['body'] = {'you_sent': request['body']}

@api.use
def log_middleware(request, response):
    print(f"Request: {request['method']} {request['path']} - Body: {request['body']}")

if __name__ == '__main__':
    run()
