        response_body = json.dumps(self.body).encode('utf-8')
        headers = ''.join(f"{key}: {value}\r\n" for key, value in self.headers.items())
        return f"HTTP/1.1 {self.status_code} OK\r\n{headers}\r\n".encode('utf-8') + response_body

class Router:
    def __init__(self):
        self.routes = {}

    def add_route(self, method, path, handler):
