        self.method = method
        self.path = path
        self.query_params = query_params
        self.body = body

class Response:
    def __init__(self):
        self.status_code = 200
        self.headers = {'Content-Type': 'application/json'}
        self.body = {}

    def set_status(self, code):
        self.status_code = code

    def set_header(self, key, value):
        self.headers[key] = value

    def json(self, data):
        self.body = data

    def to_http_response(self):
        response_body = json.dumps(self.body).encode('utf-8')
        self.headers['Content-Length'] = str(len(response_body))
        response_line = f"HTTP/1.1 {self.status_code} OK" if self.status_code == 200 else f"HTTP/1.1 {self.status_code} ERROR"
        headers = ''.join(f"{key}: {value}\r\n" for key, value in self.headers.items())
        return f"{response_line}\r\n{headers}\r\n".encode('utf-8') + response_body

