from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs

# Simple Request and Response classes.
class Request:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.method = handler.command
        self.path = handler.path
        self.headers = handler.headers
        self.query = {}
        self.body = None
        self._parse_url(handler.path)
        self._parse_body(handler)

    def _parse_url(self, path):
        parsed = urlparse(path)
        self.path = parsed.path
        self.query = parse_qs(parsed.query)

    def _parse_body(self, handler):
        if self.method in ['POST', 'PUT', 'PATCH']:
            content_length = int(handler.headers.get('Content-Length', 0))
            body_bytes = handler.rfile.read(content_length) if content_length > 0 else b""
            if body_bytes:
                try:
                    # Try parsing as JSON if content type matches.
                    if 'application/json' in handler.headers.get('Content-Type', ''):
                        self.body = json.loads(body_bytes.decode('utf-8'))
                    else:
                        self.body = body_bytes.decode('utf-8')
                except Exception:
                    self.body = body_bytes.decode('utf-8')
            else:
                self.body = None

class Response:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self._handler = handler
        self._headers = {'Content-Type': 'application/json'}
        self._status_code = 200
        self._has_sent = False

    def set_header(self, key, value):
        self._headers[key] = value

    def status(self, code):
        self._status_code = code

    def json(self, data):
        if self._has_sent:
            return
        body = json.dumps(data)
        self._handler.send_response(self._status_code)
        for key, value in self._headers.items():
            self._handler.send_header(key, value)
        self._handler.end_headers()
        self._handler.wfile.write(body.encode('utf-8'))
        self._has_sent = True

    def send(self, data):
        # Allow sending plain text or other content.
        if self._has_sent:
            return
        body = data if isinstance(data, bytes) else str(data)
        self._handler.send_response(self._status_code)
        for key, value in self._headers.items():
            self._handler.send_header(key, value)
        self._handler.end_headers()
        if isinstance(body, bytes):
            self._handler.wfile.write(body)
        else:
            self._handler.wfile.write(body.encode('utf-8'))
        self._has_sent = True

# Router to store endpoints for different HTTP methods.
class Router:
    def __init__(self):
        self.routes = {'GET': [], 'POST': [], 'PUT': [], 'DELETE': [], 'PATCH': []}

    def add_route(self, method, path_pattern, handler):
        # Convert "path/:id" to regex pattern
        pattern = re.sub(r":(\w+)", r"(?P<\1>[^/]+)", path_pattern)
        pattern = f"^{pattern}$"
        self.routes[method.upper()].append((re.compile(pattern), handler))

    def match(self, method, path):
        for pattern, handler in self.routes.get(method.upper(), []):
            match = pattern.match(path)
            if match:
                return handler, match.groupdict()  # route parameters
        return None, None

# The main application class.
class App:
    def __init__(self):
        self.router = Router()
        self.middlewares = []

    def route(self, path, methods=['GET']):
        def decorator(func):
            for m in methods:
                self.router.add_route(m, path, func)
            return func
        return decorator

    def use(self, middleware_func):
        # Middleware should be a callable taking (req, res, next)
        self.middlewares.append(middleware_func)

    def _handle_middlewares(self, req, res, handler_func):
        # Build a chain of middleware functions.
        middlewares = self.middlewares[:]

        def _run(index):
            if index < len(middlewares):
                def next_func():
                    _run(index + 1)
                middleware = middlewares[index]
                middleware(req, res, next_func)
            else:
                # Final handler call (if no middleware ends the chain).
                # Extract route parameters if any.
                handler_func(req, res)
        _run(0)

    def handle_request(self, handler: BaseHTTPRequestHandler):
        req = Request(handler)
        res = Response(handler)

        # Find matching route handler.
        route_handler, params = self.router.match(req.method, req.path)
        if route_handler is None:
            res.status(404)
            res.json({'error': 'Not Found'})
            return

        # Attach route parameters to request.
        req.params = params

        # Process middleware chain, then final handler.
        try:
            self._handle_middlewares(req, res, route_handler)
        except Exception as ex:
            res.status(500)
            res.json({'error': 'Internal Server Error', 'details': str(ex)})

    def run(self, host='localhost', port=8000):
        app = self

        class CustomHandler(BaseHTTPRequestHandler):
            def do_GET(self):
                app.handle_request(self)

            def do_POST(self):
                app.handle_request(self)

            def do_PUT(self):
                app.handle_request(self)

            def do_PATCH(self):
                app.handle_request(self)

            def do_DELETE(self):
                app.handle_request(self)

            def log_message(self, format, *args):
                # Overriding to prevent default logging.
                return

        httpd = HTTPServer((host, port), CustomHandler)
        print(f"Serving on http://{host}:{port}")
        httpd.serve_forever()


