import json
import socketserver
from http.server import BaseHTTPRequestHandler, HTTPServer
from urllib.parse import urlparse, parse_qs

###############################################################################
# Request and Response Abstractions
###############################################################################

class Request:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.handler = handler
        self.method = handler.command
        self.path = urlparse(handler.path).path
        self.query = parse_qs(urlparse(handler.path).query)
        self.headers = {k: v for k, v in handler.headers.items()}
        self._body = None

    @property
    def body(self):
        if self._body is None:
            length = self.handler.headers.get('Content-Length')
            if length:
                self._body = self.handler.rfile.read(int(length))
            else:
                self._body = b""
        return self._body

    def json(self):
        try:
            return json.loads(self.body.decode("utf-8"))
        except Exception:
            return None


class Response:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.handler = handler
        self._headers_sent = False

    def send(self, data, status=200, content_type="text/plain"):
        self.handler.send_response(status)
        self.handler.send_header("Content-Type", content_type)
        content = data.encode("utf-8") if isinstance(data, str) else data
        self.handler.send_header("Content-Length", str(len(content)))
        self.handler.end_headers()
        self.handler.wfile.write(content)
        self._headers_sent = True

    def send_json(self, data, status=200):
        json_data = json.dumps(data)
        self.send(json_data, status=status, content_type="application/json")


###############################################################################
# Core Application & Routing
###############################################################################

class Application:
    def __init__(self):
        # routes: { method: { path: (handler_function, [middleware,...]) } }
        self.routes = {}
        self.global_middleware = []

    def add_middleware(self, middleware_func):
        """
        Adds a global middleware function that runs before each request.
        Middleware signature: fn(request, response, next_func)
        """
        self.global_middleware.append(middleware_func)

    def route(self, path, methods=["GET"], middleware=None):
        """
        Decorator to register a route.
        'middleware' is an optional list of middleware functions to run for this route.
        """
        if middleware is None:
            middleware = []

        def decorator(func):
            for method in methods:
                method = method.upper()
                self.routes.setdefault(method, {})
                self.routes[method][path] = (func, middleware)
            return func
        return decorator

    def handle_request(self, handler: BaseHTTPRequestHandler):
        req = Request(handler)
        res = Response(handler)

        method_routes = self.routes.get(req.method, {})
        route_entry = method_routes.get(req.path, None)

        if not route_entry:
            # No matching route
            res.send_json({"error": "Not Found"}, status=404)
            return

        route_handler, route_middleware = route_entry

        # Merge global middleware first then route-specific middleware
        middleware_chain = self.global_middleware + route_middleware

        # The final handler to call after middleware chain finishes.
        def final_handler():
            route_handler(req, res)

        # Execute middleware chain recursively.
        def execute_middleware(index):
            if index < len(middleware_chain):
                current_middleware = middleware_chain[index]
                # Each middleware gets (req, res, next_func)
                def next_func():
                    execute_middleware(index + 1)
                current_middleware(req, res, next_func)
            else:
                final_handler()

        try:
            execute_middleware(0)
        except Exception as e:
            # Basic error handling.
            res.send_json({"error": "Internal Server Error", "message": str(e)}, status=500)

    def run(self, host="127.0.0.1", port=8000):
        """
        Run the HTTP server.
        """
        # Define a RequestHandler class that calls our app's handle_request.
        app = self

        class CustomHandler(BaseHTTPRequestHandler):
            def do_OPTIONS(self):
                self.send_response(200)
                self.send_header("Access-Control-Allow-Origin", "*")
                self.send_header("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
                self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
                self.end_headers()

            def do_GET(self):
                app.handle_request(self)

            def do_POST(self):
                app.handle_request(self)

            def do_PUT(self):
                app.handle_request(self)

            def do_DELETE(self):
                app.handle_request(self)

            def log_message(self, format, *args):
                # Override to reduce default logging if desired.
                return

        server = HTTPServer((host, port), CustomHandler)
        print(f"Server running on http://{host}:{port}")
        try:
            server.serve_forever()
        except KeyboardInterrupt:
            print("Shutting down server...")
            server.server_close()

