#!/usr/bin/env python3
"""
A simple REST API framework in Python built from scratch.
Features:
 • Routing for different HTTP methods and paths
 • JSON request body parsing
 • Middleware support
Usage:
 • Define routes using the @api.route decorator.
 • Register middleware via api.use().
 • Run the server with api.run().
"""

import json
import urllib.parse
from http.server import BaseHTTPRequestHandler, HTTPServer


class Request:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.method = handler.command
        # Parse URL and query parameters.
        parsed_url = urllib.parse.urlparse(handler.path)
        self.path = parsed_url.path
        self.query = urllib.parse.parse_qs(parsed_url.query)
        self.headers = dict(handler.headers)
        self.body = self._parse_body(handler)

    def _parse_body(self, handler):
        content_length = int(handler.headers.get("Content-Length", 0))
        if content_length:
            raw_body = handler.rfile.read(content_length)
            # Attempt to parse JSON; if it fails, return raw bytes.
            try:
                return json.loads(raw_body.decode("utf-8"))
            except Exception:
                # If not JSON, return as raw data.
                return raw_body
        return None


class Response:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.handler = handler
        self._headers_sent = False

    def set_header(self, key, value):
        self.handler.send_header(key, value)

    def status(self, code):
        self.handler.send_response(code)

    def send(self, body, code=200, content_type="text/plain"):
        # Write headers and body.
        self.status(code)
        self.set_header("Content-Type", content_type)
        self.handler.end_headers()
        if isinstance(body, str):
            self.handler.wfile.write(body.encode("utf-8"))
        else:
            self.handler.wfile.write(body)

    def json(self, obj, code=200):
        body = json.dumps(obj)
        self.send(body, code, content_type="application/json")


def run_middlewares(req, res, middlewares, final_handler):
    """Recursively chain middleware execution."""
    def execute(index):
        # If there are no more middleware functions, call the final route handler.
        if index == len(middlewares):
            return final_handler()
        # Current middleware function.
        def next_func():
            return execute(index + 1)
        # Call middleware with req, res and next function.
        return middlewares[index](req, res, next_func)
    return execute(0)


class SimpleAPI:
    def __init__(self, host="localhost", port=8000):
        # routes is a dictionary with keys as tuple (HTTP_METHOD, PATH)
        self.routes = {}
        self.middlewares = []
        self.host = host
        self.port = port

    def route(self, path, methods=["GET"]):
        """
        Decorator to register a route handler for a specific path and HTTP method(s).
        Example:
            @api.route("/hello", methods=["GET"])
            def hello(req, res):
                res.send("Hello, world!")
        """
        def decorator(func):
            for method in methods:
                self.routes[(method.upper(), path)] = func
            return func
        return decorator

    def use(self, middleware):
        """
        Register a middleware function.
        Middleware functions should be defined as:
            def middleware(req, res, next):
                # Do something (e.g., logging, authentication)
                next()
        """
        self.middlewares.append(middleware)

    def _handle_request(self, handler: BaseHTTPRequestHandler):
        # Create request and response objects
        req = Request(handler)
        res = Response(handler)

        # Determine the appropriate route handler.
        route_key = (req.method.upper(), req.path)
        route_handler = self.routes.get(route_key, None)

        def final_handler():
            if route_handler is not None:
                try:
                    return route_handler(req, res)
                except Exception as e:
                    res.json({"error": str(e)}, code=500)
            else:
                res.json({"error": "Not Found"}, code=404)

        # Run middlewares and then the final handler.
        run_middlewares(req, res, self.middlewares, final_handler)

    def run(self):
        # Define a custom RequestHandler that uses our SimpleAPI instance.
        api = self

        class CustomHandler(BaseHTTPRequestHandler):
            def do_GET(self):
                api._handle_request(self)

            def do_POST(self):
                api._handle_request(self)

            def do_PUT(self):
                api._handle_request(self)

            def do_DELETE(self):
                api._handle_request(self)

            def log_message(self, format, *args):
                # Override to prevent printing default logging.
                return

        server_address = (self.host, self.port)
        httpd = HTTPServer(server_address, CustomHandler)
        print(f"Serving on http://{self.host}:{self.port}")
        try:
            httpd.serve_forever()
        except KeyboardInterrupt:
            print("\nServer stopped.")
            httpd.server_close()


