"""
A simple REST API framework built from scratch.
It supports routing, JSON parsing, and basic middleware.
Usage:
    - Define routes using the @app.route decorator.
    - Add middleware using app.add_middleware.
    - Start the server via app.run(port).
"""

import json
import re
from http.server import BaseHTTPRequestHandler, HTTPServer

# ------------------------------------------------------------------------------
# Data structures for Request and Response
# ------------------------------------------------------------------------------

class Request:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.method = handler.command
        self.path = handler.path.split('?')[0]
        self.headers = handler.headers
        self.query_string = self._parse_query_string(handler.path)
        self.body = self._read_body(handler)
        self.json = self._parse_json()

    def _read_body(self, handler: BaseHTTPRequestHandler):
        content_length = handler.headers.get('Content-Length')
        if content_length:
            try:
                length = int(content_length)
                return handler.rfile.read(length)
            except Exception:
                return None
        return None

    def _parse_json(self):
        content_type = self.headers.get('Content-Type', '')
        if self.body and 'application/json' in content_type:
            try:
                return json.loads(self.body.decode('utf-8'))
            except Exception:
                return None
        return None

    def _parse_query_string(self, path):
        parts = path.split('?', 1)
        qs = {}
        if len(parts) == 2:
            query = parts[1]
            pairs = query.split('&')
            for pair in pairs:
                if '=' in pair:
                    k, v = pair.split('=', 1)
                    qs[k] = v
        return qs


class Response:
    def __init__(self, handler: BaseHTTPRequestHandler):
        self.handler = handler
        self.status_code = 200
        self.headers = {"Content-Type": "application/json"}
        self.body = None

    def set_header(self, key, value):
        self.headers[key] = value

    def json(self, data, status_code=200):
        self.body = json.dumps(data).encode('utf-8')
        self.status_code = status_code
        self.set_header("Content-Type", "application/json")

    def text(self, data, status_code=200):
        if isinstance(data, str):
            self.body = data.encode('utf-8')
        else:
            self.body = data
        self.status_code = status_code
        self.set_header("Content-Type", "text/plain")

    def send(self):
        self.handler.send_response(self.status_code)
        for key, value in self.headers.items():
            self.handler.send_header(key, value)
        self.handler.end_headers()
        if self.body:
            self.handler.wfile.write(self.body)

# ------------------------------------------------------------------------------
# Application Framework
# ------------------------------------------------------------------------------

class Application:
    def __init__(self):
        # routes are stored as a list of tuples: (method, path_regex, handler)
        self.routes = []
        # middleware: list of functions: middleware(request, response, next)
        self.middleware = []

    def add_route(self, method: str, path: str, handler):
        # Convert path to regex (exact match for now, but can be extended)
        path_regex = re.compile(f"^{path}$")
        self.routes.append((method.upper(), path_regex, handler))

    def route(self, path, methods=["GET"]):
        def decorator(func):
            for method in methods:
                self.add_route(method, path, func)
            return func
        return decorator

    def add_middleware(self, middleware_func):
        """
        Middleware functions must have the signature:
            middleware(request, response, next)
        where "next" is the function to call to continue the chain.
        """
        self.middleware.append(middleware_func)

    def _match_route(self, request: Request):
        for method, path_regex, handler in self.routes:
            if request.method.upper() == method and path_regex.match(request.path):
                return handler
        return None

    def _execute_middleware(self, request, response, final_handler):
        """
        Execute middleware chain and eventually call the final_handler.
        Middleware are executed in order.
        """
        def create_chain(index):
            if index < len(self.middleware):
                def next_step():
                    return self.middleware[index](request, response, create_chain(index + 1))
                return next_step
            else:
                return lambda: final_handler(request, response)
        # Start chain
        return create_chain(0)()

    def handle_request(self, handler: BaseHTTPRequestHandler):
        request = Request(handler)
        response = Response(handler)

        # Find the route handler:
        route_handler = self._match_route(request)
        if route_handler is None:
            response.json({"error": "Not Found"}, status_code=404)
            response.send()
            return

        # Define final handler which will be executed after middleware.
        def final_handler(req, res):
            # Call the route handler
            try:
                result = route_handler(req)
                if isinstance(result, dict):
                    res.json(result)
                elif isinstance(result, tuple):
                    # Allows (data, status_code)
                    data, status_code = result
                    if isinstance(data, dict):
                        res.json(data, status_code=status_code)
                    else:
                        res.text(str(data), status_code=status_code)
                else:
                    # Fallback: output as text
                    res.text(str(result))
            except Exception as e:
                res.json({"error": str(e)}, status_code=500)

