from typing import Dict, List, Callable, Any, Optional, Tuple
from urllib.parse import parse_qs, unquote
import traceback


class HTTPRequest:
    def __init__(self, method: str, path: str, headers: Dict[str, str], 
                 body: str, query_params: Dict[str, List[str]]):
        self.method = method
        self.path = path
        self.headers = headers
        self.body = body
        self.query_params = query_params
        self._json_data = None

    @property
    def json(self) -> Optional[Dict[str, Any]]:
        if self._json_data is None and self.body:
            try:
                self._json_data = json.loads(self.body)
            except json.JSONDecodeError:
                return None
        return self._json_data


class HTTPResponse:
    def __init__(self, body: str = "", status_code: int = 200, 
                 headers: Optional[Dict[str, str]] = None):
        self.body = body
        self.status_code = status_code
        self.headers = headers or {}

        if 'Content-Type' not in self.headers:
            self.headers['Content-Type'] = 'text/plain'

    def json(self, data: Any, status_code: int = 200) -> 'HTTPResponse':
        self.body = json.dumps(data)
        self.status_code = status_code
        self.headers['Content-Type'] = 'application/json'
        return self

    def to_http_string(self) -> str:
        status_messages = {
            200: 'OK', 201: 'Created', 400: 'Bad Request',
            404: 'Not Found', 405: 'Method Not Allowed',
            500: 'Internal Server Error'
        }

        status_line = f"HTTP/1.1 {self.status_code} {status_messages.get(self.status_code, 'Unknown')}"

        self.headers['Content-Length'] = str(len(self.body.encode('utf-8')))
        header_lines = [f"{key}: {value}" for key, value in self.headers.items()]

        return f"{status_line}\r\n" + "\r\n".join(header_lines) + "\r\n\r\n" + self.body


class Route:
    def __init__(self, pattern: str, handler: Callable, methods: List[str]):
        self.pattern = pattern
        self.handler = handler
        self.methods = [method.upper() for method in methods]
        self.regex = self._compile_pattern(pattern)

    def _compile_pattern(self, pattern: str) -> re.Pattern:
        # Convert route patterns like /users/{id} to regex
        regex_pattern = re.sub(r'\{([^}]+)\}', r'(?P<\1>[^/]+)', pattern)
        regex_pattern = f"^{regex_pattern}$"
        return re.compile(regex_pattern)

    def matches(self, path: str, method: str) -> Tuple[bool, Dict[str, str]]:
        if method.upper() not in self.methods:
            return False, {}

        match = self.regex.match(path)
        if match:
            return True, match.groupdict()
        return False, {}


class Middleware:
    def process_request(self, request: HTTPRequest) -> Optional[HTTPResponse]:
        """Process request before routing. Return response to short-circuit."""
        return None

    def process_response(self, request: HTTPRequest, response: HTTPResponse) -> HTTPResponse:
        """Process response after handler execution."""
        return response


class CORSMiddleware(Middleware):
    def __init__(self, allow_origins: List[str] = None, 
                 allow_methods: List[str] = None,
                 allow_headers: List[str] = None):
        self.allow_origins = allow_origins or ['*']
        self.allow_methods = allow_methods or ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS']
        self.allow_headers = allow_headers or ['Content-Type', 'Authorization']

    def process_request(self, request: HTTPRequest) -> Optional[HTTPResponse]:
        if request.method == 'OPTIONS':
            response = HTTPResponse(status_code=200)
            self._add_cors_headers(response)
            return response
        return None

    def process_response(self, request: HTTPRequest, response: HTTPResponse) -> HTTPResponse:
        self._add_cors_headers(response)
        return response

    def _add_cors_headers(self, response: HTTPResponse):
        response.headers['Access-Control-Allow-Origin'] = ', '.join(self.allow_origins)
        response.headers['Access-Control-Allow-Methods'] = ', '.join(self.allow_methods)
